/// Look up a phoneme symbol's token id.
pub fn token(symbol: char) -> Option<u16> {
    VOCAB
        .binary_search_by_key(&symbol, |(sym, _)| *sym)
        .ok()
        .map(|index| VOCAB[index].1)
}
